"""sklearn.exceptions — Common warning and error classes."""


class NotFittedError(ValueError, AttributeError):
    """Raised when an estimator is used before fitting."""
    pass


class ConvergenceWarning(UserWarning):
    """Warning issued when an optimisation does not converge."""
    pass


class DataConversionWarning(UserWarning):
    """Warning issued when data is converted to a different dtype."""
    pass
